mapper.select:
SELECT * FROM consult

    AND type=#{type}

ORDER BY consult_date DESC, id DESC
LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE consult
SET type=#{type}, name=#{name}, phone=#{phone}, gender=#{gender},
    interest=#{interest}, content=#{content}, result=#{result},
    consult_date=#{consultDate}, staff_name=#{staffName}
WHERE id=#{id}
